-- QA Engineer Roadmap seed.
-- Idempotent seed. Safe to rerun.
BEGIN;
CREATE EXTENSION IF NOT EXISTS pgcrypto;

DROP TABLE IF EXISTS seed_edge;
DROP TABLE IF EXISTS seed_node_resource;
DROP TABLE IF EXISTS seed_node_skill;
DROP TABLE IF EXISTS seed_node;
DROP TABLE IF EXISTS seed_resource;
DROP TABLE IF EXISTS seed_skill;
DROP TABLE IF EXISTS seed_roadmap_map;

DELETE FROM public.progress_event WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.slug = 'qa-engineer-roadmap');
DELETE FROM public.user_node_progress WHERE roadmap_enrollment_id IN (SELECT e.roadmap_enrollment_id FROM public.roadmap_enrollment e JOIN public.roadmap_version rv ON rv.roadmap_version_id = e.roadmap_version_id JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.slug = 'qa-engineer-roadmap');
DELETE FROM public.roadmap_enrollment WHERE roadmap_version_id IN (SELECT rv.roadmap_version_id FROM public.roadmap_version rv JOIN public.roadmap r ON r.roadmap_id = rv.roadmap_id WHERE r.slug = 'qa-engineer-roadmap');
DELETE FROM public.roadmap WHERE slug = 'qa-engineer-roadmap';

    'QA Engineer',
    'qa-engineer',
    'Quality assurance engineering path covering testing fundamentals, manual testing, web/API foundations, test management, API testing, automation programming, UI automation, mobile testing, performance, security, accessibility, CI/CD, AI-assisted QA, specialization, and capstone portfolio work.',
    'Quality Assurance',
    true
) ON CONFLICT (slug) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, category = EXCLUDED.category, is_active = true, updated_at = now();

DROP TABLE IF EXISTS seed_roadmap_map;
CREATE TEMP TABLE seed_roadmap_map AS
WITH role_row AS (SELECT career_role_id FROM public.career_role WHERE slug = 'qa-engineer'), inserted_roadmap AS (
SELECT career_role_id, (SELECT user_id FROM public."user" WHERE username_normalized = 'contentmanager2' LIMIT 1), 'QA Engineer Roadmap', 'qa-engineer-roadmap', 'A structured learning path for becoming a QA engineer, covering testing fundamentals, manual testing, web and API foundations, test management, API testing, automation programming, UI automation, mobile testing, performance, security, accessibility, CI/CD, AI-assisted QA, specialization, and portfolio-ready quality engineering work.', 'public'
FROM role_row
    RETURNING roadmap_id
), inserted_version AS (
SELECT
    roadmap_id,
    1,
    1,
    0,
    0,
    'initial',
    'published',
    'QA Engineer Roadmap',
    'A practical QA engineering roadmap that moves from testing foundations to production-quality validation through guided topics, checkpoints, optional practice projects, and required milestone projects.',
    420,
    'TB',
    'custom',
    now()
FROM inserted_roadmap
    RETURNING roadmap_version_id, roadmap_id
) SELECT roadmap_id, roadmap_version_id FROM inserted_version;

-- Skills.
DROP TABLE IF EXISTS seed_skill;
CREATE TEMP TABLE seed_skill (slug text PRIMARY KEY, name text NOT NULL, category text NOT NULL, description text NOT NULL) ON COMMIT DROP;









