('chk-final-qa-review', 'ph-portfolio-capstone', 90, 'checkpoint', 'assessment', NULL, NULL, 'Final QA Roadmap Review Gate', 'Final roadmap checkpoint for Portfolio, Interview Readiness, and Capstone. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the software quality assurance path.', 'checkpoint', 2, 'advanced', '{"reviewFocus":"Final roadmap checkpoint for Portfolio, Interview Readiness, and Capstone. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the software quality assurance path.","reviewCriteria":["Summarize completed phases, projects, and major skill groups.","Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.","List remaining gaps or specialization topics for future learning.","State that the checkpoint is a planning review, not proof of job readiness."],"source":"roadmap.sh/qa"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent software quality assurance learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb),
('proj-qa-capstone', 'ph-portfolio-capstone', 100, 'project', NULL, NULL, NULL, 'Required QA Engineer Capstone Project', 'Capstone project: Test a realistic web application end-to-end with test strategy, manual suite, API automation, UI automation, accessibility/security checks, performance smoke test, CI reporting, and final quality report.', 'side', 8, 'advanced', '{"whatToBuild":"Test a realistic web application end-to-end with test strategy, manual suite, API automation, UI automation, accessibility/security checks, performance smoke test, CI reporting, and final quality report.","buildSteps":["Define the QA Engineer Capstone Project scenario and list the specific items to demonstrate: API behavior, CI checks, security controls, test evidence, automation flow.","Choose a coherent product or case-study scenario that can integrate the strongest projects from the roadmap.","Define the architecture, data or workflow model, user path, and review evidence before implementation.","Build the core artifact end-to-end with scoped features rather than disconnected demos.","Add validation evidence appropriate to the role, such as tests, metrics, query checks, playtest notes, traces, screenshots, or incident notes.","Prepare a case study explaining decisions, trade-offs, limitations, and what would need further review for real deployment.","Package the repository or artifact so another person can reproduce or inspect the result.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim."],"source":"roadmap.sh/qa","nodeKey":"proj-qa-capstone"}'::jsonb, true, true, '["Apply Test Planning and Strategy, Testing, Portfolio Communication through a focused QA Engineer Capstone Project artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The a portfolio-ready QA Engineer Capstone Project case study and integrated artifact is available for review.","The QA Engineer Capstone Project scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb),
('proj-mock-release-go-no-go', 'ph-portfolio-capstone', 111, 'project', NULL, NULL, NULL, 'Mock Release Go/No-Go Report', 'Capstone project: Prepare a release readiness report with quality signals, defects, risks, and recommendation.', 'side', 2, 'advanced', '{"whatToBuild":"Prepare a release readiness report with quality signals, defects, risks, and recommendation.","buildSteps":["Define the Mock Release Go/No-Go Report scenario, target user or reviewer, and the specific Portfolio, Interview Readiness, and Capstone concepts it will demonstrate.","Choose a coherent product or case-study scenario that can integrate the strongest projects from the roadmap.","Define the architecture, data or workflow model, user path, and review evidence before implementation.","Build the core artifact end-to-end with scoped features rather than disconnected demos.","Add validation evidence appropriate to the role, such as tests, metrics, query checks, playtest notes, traces, screenshots, or incident notes.","Prepare a case study explaining decisions, trade-offs, limitations, and what would need further review for real deployment.","Package the repository or artifact so another person can reproduce or inspect the result.","Create a review checklist that connects the artifact to the relevant skills and roadmap segment.","Write a limitation and risk section so the project is presented as reviewable evidence, not a certification claim."],"source":"roadmap.sh/qa","nodeKey":"proj-mock-release-go-no-go"}'::jsonb, false, true, '["Apply Release Readiness through a focused Mock Release Go/No-Go Report artifact.","Integrate multiple roadmap areas into one coherent case study rather than isolated exercises.","Explain the main design, data, tooling, workflow, or review decisions behind the project.","Validate the result with evidence that another person can inspect.","Document assumptions, limitations, and a concrete follow-up improvement."]'::jsonb, '["The a portfolio-ready Mock Release Go/No-Go Report case study and integrated artifact is available for review.","The Mock Release Go/No-Go Report scope, setup path, input data or scenario, and expected output are documented.","The main workflow runs or can be inspected through a notebook, repository, dashboard, prototype, report, configuration, or case study.","The case study connects implementation decisions to relevant roadmap skills and explains why alternatives were not chosen.","Validation evidence is included and directly relates to the project brief.","The notes identify trade-offs, limitations, and one next improvement without claiming mastery or job readiness.","The project is packaged so a reviewer can understand the artifact without live mentoring."]'::jsonb);
